sql:
SELECT COUNT(athletes.athlete_id) as Number_of_Athletes
FROM athletes
JOIN races ON athletes.nationality = races.location_id;

external_knowledge:
- 'successful racers' refers to athletes who have won races (position = 1);
- 'top spot' means the first position in a race;
- 'couple of triumphs' refers to 2 or more victories.

sql:
SELECT races.race_name, race_categories.category_rules
FROM races
INNER JOIN race_categories ON races.race_id = race_categories.race_id;

SELECT DISTINCT team_name, sponsor, contact_email, contact_phone, team_logo, team_website 
FROM teams 
ORDER BY team_name;

SELECT rr.overall_position, a.first_name, a.last_name, rr.scored_points
FROM athletes a
JOIN race_results rr ON a.athlete_id = rr.athlete_id;

SELECT athlete_id, team_id
FROM team_memberships
WHERE join_date > '2000-12-31';

SELECT * 
FROM athletes 
WHERE team_id IN (SELECT DISTINCT team_id FROM race_results);

external_knowledge:
- 'fleet-footed racers' refers to athletes with a high average speed;
- 'teams that sail on the roadways of the competition' metaphorically refers to teams participating in road races;
- 'average swiftness surpasses the thirty-kilometer watch' means athletes with an average speed above 30 km/h.

sql:
SELECT COUNT(*)
FROM athlete_performance
WHERE metric_name = 'Average Speed' AND metric_value > 30;
